class Solution:
    def selfDividingNumbers(self, left: int, right: int) -> List[int]:
        def ok(x):
            for d in map(int, str(x)):
                if d == 0 or x % d: return False
            return True
        return [x for x in range(left, right + 1) if ok(x)]

