class Solution {
public:
    vector<int> selfDividingNumbers(int left, int right) {
        vector<int> ans;
        auto ok=[](int x){
            for(int t=x;t;t/=10){ int d=t%10; if(!d||x%d) return false; }
            return true;
        };
        for(int x=left;x<=right;x++) if(ok(x)) ans.push_back(x);
        return ans;
    }
};

