int* selfDividingNumbers(int left, int right, int* retSize) {
    int* ans = malloc((right-left+1)*4); *retSize = 0;
    for (int x = left; x <= right; x++) {
        int t = x, ok = 1;
        for (; t; t /= 10) { int d = t % 10; if (!d || x % d) { ok = 0; break; } }
        if (ok) ans[(*retSize)++] = x;
    }
    return ans;
}
